import{_ as r}from"./Menu.bf643b41.js";import{u as o}from"./composables.a20be60a.js";import{r as e,a as n,e as l,b as u,f as t,o as c}from"./entry.b2c8d4ee.js";const d=""+new URL("umas-maquette.8234770e.jpg",import.meta.url).href,m={class:"banniere"},p=t('<div class="margium-l marge-haute-l"><div class="espacium"><h1>Un Mus\xE9e \xE0 Soi</h1><div class="colonnes"><div class="colonne"><div class="projettitre">Contexte</div> Contrat freelance : Cr\xE9ation d&#39;une web-expo </div><div class="colonne"><div class="projettitre">P\xE9riode</div> Novembre 2020 \xE0 ao\xFBt 2021 </div><div class="colonne"></div><div class="colonne"><a href="https://unmuseeasoi.org/" class="lienapp" target="_blank">Visiter la web-expo</a></div></div></div></div>',1),v=t('<article class="margium-l marge-haute-l marge-basse-l"><div class="espacium"><div class="coldroite"><p>Un Mus\xE9e \xE0 Soi, et une exposition sur le f\xE9minisme. Elle aborde les th\xE8mes du genre, de l&#39;histoire des luttes f\xE9ministes, de la sexualit\xE9 et pr\xE9sente des femmes embl\xE9matiques li\xE9es \xE0 la ville de Tournai.<br><br> Cette exposition a \xE9t\xE9 commandit\xE9e par la ville de Tournai aupr\xE8s du master de mus\xE9ographie d&#39;Arras. La production a \xE9t\xE9 assur\xE9e par 4 mus\xE9ographes, une illustratrice et un UI UX Designer et d\xE9veloppeur. Nous avions comme objectif de r\xE9aliser une exposition num\xE9rique pour remplacer celle qui \xE9tait pr\xE9vue dans le mus\xE9e de la ville en raison des conditions li\xE9es au COVID. </p><h2>La demande</h2><p> Les mus\xE9ographes avaient \xE9tabli des recherches et avaient structur\xE9 leurs propos dans un document sur lequel il \xE9tait important d&#39;apporter de la forme, de l&#39;interactivit\xE9 et des d&#39;\xE9prouv\xE9s ses contenus par des tests utilisateurs pour v\xE9rifier leur compr\xE9hensibilit\xE9 et ainsi que la pertinence des interactions li\xE9es \xE0 ce contenu. <br>Mon r\xF4le a \xE9t\xE9 de : <ul><li> Accompagner la conception de la web-expo </li><li> Concevoir le design d&#39;interface </li><li> Concevoir les \xE9l\xE9ments interactifs </li><li> Participer \xE0 la gestion de projet num\xE9rique </li><li> Mener des tests utilisateurs </li></ul></p><h2>Maquettes</h2><img src="'+d+'" loading="lazy" alt="Maquette du site Un mus\xE9e \xE0 Soi"><p>De nombreux wireframes et de maquettes ont \xE9t\xE9 r\xE9alis\xE9es pour mettre en forme et en valeur les contenus r\xE9dig\xE9s par les mus\xE9ographes. On note de nombreux \xE9l\xE9ments interactifs dans ce type de maquette, car la web-exposition se veut \xEAtre cr\xE9ative et \xE0 sortir des codes des sites web institutionnels. On peut noter des cartels, des portes qui s&#39;ouvrent, de nombreux audios pour simplifier la lecture ou encore une frise chronologique pour mettre en valeur les dates majeures des combats f\xE9ministes en Belgique. <br>Avec le recul que j&#39;ai sur ce projet, je trouve qu&#39;il manque une partie gamification qui permettrait de maintenir davantage l&#39;attention et l&#39;engagement des lecteurs jusqu&#39;au bout de l&#39;\u0153uvre.</p></div></div></article>',1),x={__name:"un-musee-a-soi",setup(g){const s=e("Un Mus\xE9e \xE0 Soi - Lucas Lacroix"),i=e("");return o({title:s,meta:[{name:"description",content:i}]}),(f,h)=>{const a=r;return c(),n("div",null,[l("div",m,[u(a),p]),v])}}};export{x as default};
